import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Perguntas Frequentes","description":"Perguntas feitas por jogadores e administradores sobre o Fabric.","frontmatter":{"title":"Perguntas Frequentes","description":"Perguntas feitas por jogadores e administradores sobre o Fabric.","files":[]},"headers":[],"relativePath":"pt_br/players/faq.md","filePath":"translated/pt_br/players/faq.md","lastUpdated":1772272927000}`);var a={name:`pt_br/players/faq.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Perguntas Frequentes <a class="header-anchor" href="#h1" aria-label="Permalink to “Perguntas Frequentes”">​</a></h1><p>Há muitas perguntas feitas com frequência, então compilamos uma lista delas aqui.</p><h2 id="what-minecraft-versions-does-fabric-support" tabindex="-1">Quais versões do Minecraft são compatíveis com o Fabric? <a class="header-anchor" href="#what-minecraft-versions-does-fabric-support" aria-label="Permalink to “Quais versões do Minecraft são compatíveis com o Fabric?”">​</a></h2><p>Oficialmente, o Fabric é compatível com todas as versões do Minecraft começando da snapshot <code>18w43b</code> em diante, e versões da <code>1.14</code> em diante.</p><h2 id="where-can-i-download-published-fabric-mods" tabindex="-1">Onde eu posso baixar mods publicados do Fabric? <a class="header-anchor" href="#where-can-i-download-published-fabric-mods" aria-label="Permalink to “Onde eu posso baixar mods publicados do Fabric?”">​</a></h2><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Você sempre deve verificar se os mods são de fontes confiáveis. Leia o guia <a href="./finding-mods">Encontrando Mods Confiáveis</a> para mais informações.</p></div><p>A maioria dos autores publicam seus mods no <a href="https://modrinth.com/mods?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a> e <a href="https://www.curseforge.com/minecraft/search?class=mc-mods&amp;gameVersionTypeId=4" target="_blank" rel="noreferrer">CurseForge</a>, no entando, alguns podem preferir publicá-los em seus sites pessoais, ou em outras plataformas, como repositórios GitHub.</p><h2 id="where-can-i-find-pre-made-fabric-modpacks" tabindex="-1">Onde Posso Encontrar Modpacks Pré-Prontos para Fabric? <a class="header-anchor" href="#where-can-i-find-pre-made-fabric-modpacks" aria-label="Permalink to “Onde Posso Encontrar Modpacks Pré-Prontos para Fabric?”">​</a></h2><p>Você pode encontrar modpacks pré-prontos para o Fabric em diversas plataformas, como:</p><ul><li><a href="https://modrinth.com/modpacks?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a></li><li><a href="https://www.curseforge.com/minecraft/search?class=modpacks&amp;gameVersionTypeId=4" target="_blank" rel="noreferrer">CurseForge</a></li><li><a href="https://www.feed-the-beast.com/ftb-app" target="_blank" rel="noreferrer">Feed The Beast</a></li><li><a href="https://www.technicpack.net/modpacks" target="_blank" rel="noreferrer">Technic</a></li></ul>`,10)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};